package com.google.gson;
import static org.junit.jupiter.api.Assertions.assertEquals;
import static org.mockito.Mockito.*;

import com.google.gson.Gson;
import com.google.gson.JsonElement;
import com.google.gson.JsonPrimitive;
import java.io.StringWriter;
import java.lang.reflect.Method;
import org.junit.jupiter.api.BeforeEach;
import org.junit.jupiter.api.Test;

public class GsonToJsonTest {

  private Gson gson;

  @BeforeEach
  public void setUp() {
    gson = new Gson();
  }

  @Test
  public void testToJson_withJsonPrimitive() {
    JsonPrimitive jsonPrimitive = new JsonPrimitive("testString");
    String json = gson.toJson(jsonPrimitive);
    assertEquals("\"testString\"", json);
  }

  @Test
  public void testToJson_withJsonElement_null() {
    String json = gson.toJson((JsonElement) null);
    assertEquals("null", json);
  }

  @Test
  public void testToJson_invokesPrivateToJsonJsonElementWriter() throws Exception {
    JsonElement jsonElement = new JsonPrimitive("privateTest");
    StringWriter stringWriter = new StringWriter();

    Method toJsonMethod = Gson.class.getDeclaredMethod("toJson", JsonElement.class, java.io.Writer.class);
    toJsonMethod.setAccessible(true);
    toJsonMethod.invoke(gson, jsonElement, stringWriter);

    assertEquals("\"privateTest\"", stringWriter.toString());
  }
}
